INSERT INTO tb_lojas (id, nome, descricao, categoria, imagem_url, is_aberto, taxa_entrega_base, tempo_entrega_min, tempo_entrega_max, avaliacao_media, total_avaliacoes, end_rua, end_numero, end_cidade, end_estado, end_cep, geo_lat, geo_lng, geo_geohash, horario_domingo, horario_segunda, horario_terca, horario_quarta, horario_quinta, horario_sexta, horario_sabado) VALUES 
('loja_0001', 'Fast Kitchen', 'To sell delicious and remarkable food and drinks. That the food and drink we sell meets the highest standards of quality, freshness and seasonality and combines both modern-creative and traditional southern styles of cooking. To consistently provide our customers with impeccable service by demonstrating warmth, graciousness, efficiency, knowledge, professionalism and integrity in our work. To have every customer who comes through our doors leave impressed by Maxie’s and excited to come back again. To create and maintain a restaurant that is comprehensive and exceptional in its attention to every detail of operation. To provide all who work with us a friendly, cooperative and rewarding environment which encourages long- term, satisfying, growth employment. To keep our concept fresh, exciting and on the cutting edge of the hospitality and entertainment industry. To be a giving member of the Ithaca community and to use our restaurant to improve the quality of life in the Finger Lakes region.', 'Italiana', 'https://picsum.photos/seed/loja_0001/400', true, 11.56, 27, 45, 4.1, 1245, 'Alameda Maria Fernanda Menendes', '8372', 'Barcelos', 'MG', '50279329', -5.02957576, -109.41437645, NULL, '11:00 - 23:00', 'Fechado', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00'),
('loja_0002', 'Sugar Juice Bar', 'Culver’s Restaurant was founded by the Culver family in 1984, which eventually branched out to more than 300 franchised restaurants all over the US. Culver’s is well-known for its ButterBurger, which made the restaurant extremely famous. They also have other items which include salads, sandwiches, desserts, etc.', 'Lanches', 'https://picsum.photos/seed/loja_0002/400', false, 4.73, 22, 33, 4.4, 1637, 'Ponte Maria Fernanda Hernandes', '74529', 'Espinho', 'PE', '54081716', -36.21192857, -158.67245119, NULL, '11:00 - 23:00', 'Fechado', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00'),
('loja_0003', 'Thirsty Pizza', 'Our mission has been to help people achieve their health and wellness goals. though weve changed over the years, our values have remained the same.', 'Pizza', 'https://picsum.photos/seed/loja_0003/400', true, 9.12, 17, 30, 4.2, 1984, 'Avenida Célia Oliveira', '00901', 'Tarouca', 'MG', '45166453', -4.09135100, 135.38877354, NULL, '11:00 - 23:00', 'Fechado', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00'),
('loja_0004', 'Fat Grill', 'We earn the loyalty of the people we serve by first anticipating, then fulfilling their needs with our superior-quality products, a unique shopping experience, customer-focused service and continuous innovation, while generating long-term profitable growth for our shareholders.', 'Pizza', 'https://picsum.photos/seed/loja_0004/400', false, 10.50, 29, 47, 4.7, 1280, 'Travessa Emanuelly da Fronteira', 's/n', 'Vila Franca de Xira', 'MT', '31744555', -0.21338279, 146.41992850, NULL, '11:00 - 23:00', 'Fechado', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00'),
('loja_0005', 'Sweet Cafe', 'To ensure that each guest receives prompt, professional, friendly and courteous service. To maintain a clean, comfortable and well maintained premises for our guests and staff. To provide at a fair price – nutritional, well-prepared meals – using only quality ingredients. To ensure that all guests and staff are treated with the respect and dignity they deserve. To thank each guest for the opportunity to serve them. By maintaining these objectives we shall be assured of a fair profit that will allow us to contribute to the community we serve.', 'Doces', 'https://picsum.photos/seed/loja_0005/400', false, 12.69, 21, 36, 4.9, 471, 'Travessa Davi Luca', '805', 'Ponta Delgada', 'MG', '92580670', -49.06426876, -119.79790008, NULL, '11:00 - 23:00', 'Fechado', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00'),
('loja_0006', 'Golden Spoon', 'Yoshinoya is in business to create the structure and systems needed to allow our customers access to the majority of their away-from-home daily meal requirements on a one-stop-shop basis. All our products shall be of the highest quality and value, be healthy, nutritious and provided with outstanding personal services at the lowest possible prices consistent with a fair return on investment for our shareholders, job enhancementsecurity for our employees and a level of community involvement by everyone connected with our business. All of our products and services shall be delivered consistently and measured one satisfied customer at a time, whether by company-owned or franchised operations, in superior, clean, convenient, fun and friendly neighborhood environments. We pledge to make Yoshinoya the best place to eat and the best place to work.', 'Doces', 'https://picsum.photos/seed/loja_0006/400', false, 7.88, 29, 41, 4.3, 1906, 'Travessa Valentina', '8531', 'Rebordosa', 'AC', '03332099', -27.62935910, -97.32335612, NULL, '11:00 - 23:00', 'Fechado', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00'),
('loja_0007', '304 Deli', 'To achieve and maintain such distinction in food and wine, service, atmosphere and setting that the restaurant gains a first class reputation for gastronomy, gracious and informed hospitality, comfort and beauty which draws new and repeat customers year after year. To achieve the above whilst upholding staff policies and practices which promote a fair and positive working environment. To be aware of and act on our responsibilities as a good corporate citizen to  provide a safe, clean and attractive place for guests to enjoy and for employees to work in - ensure ecologically sound management practices at the restaurant and in our surrounding gardens and woods - undertake meaningful involvement of Restaurant Les Fougères in selected charitable activities in our community and region.', 'Pizza', 'https://picsum.photos/seed/loja_0007/400', false, 10.45, 19, 30, 4.0, 1911, 'Avenida Ayla Raia', 's/n', 'Lamego', 'MA', '51486962', -7.93376959, 104.62510477, NULL, '11:00 - 23:00', 'Fechado', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00'),
