('loja_0203', 'Belly Spoon', 'We earn the loyalty of the people we serve by first anticipating, then fulfilling their needs with our superior-quality products, a unique shopping experience, customer-focused service and continuous innovation, while generating long-term profitable growth for our shareholders.', 'Italiana', 'https://picsum.photos/seed/loja_0203/400', true, 13.09, 26, 49, 4.7, 403, 'Travessa Maria Fernanda', '08129', 'Valpaços', 'GO', '52431253', 22.19657888, -105.15503083, NULL, '11:00 - 23:00', 'Fechado', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00', '11:00 - 23:00'),
